function solve(nums) {
    const N = nums.length;
    if (N === 0) {
        return 0;
    }

    // 1. Preprocessing: Map values to their indices
    const valueToIndices = new Map();
    for (let i = 0; i < N; i++) {
        const val = nums[i];
        if (!valueToIndices.has(val)) {
            valueToIndices.set(val, []);
        }
        valueToIndices.get(val).push(i);
    }

    let totalCount = 0;

    // M: Map {OR_value: start_index}. start_index is the smallest index R such that OR(nums[R...j]) = OR_value.
    // M stores information for the subarray ending at j-1.
    let M = new Map();

    for (let j = 0; j < N; j++) {
        const currentNum = nums[j];
        let nextM = new Map();

        // 1. Update existing OR values from M (representing subarrays ending at j-1)
        for (const [V_prev, R_prev] of M.entries()) {
            const V_new = V_prev | currentNum;

            // We only store the minimum starting index R_prev for V_new
            if (!nextM.has(V_new) || R_prev < nextM.get(V_new)) {
                nextM.set(V_new, R_prev);
            }
        }

        // 2. Add the subarray of length 1: [nums[j]]
        // The OR value is currentNum, starting at index j.
        if (!nextM.has(currentNum) || j < nextM.get(currentNum)) {
             nextM.set(currentNum, j);
        }

        M = nextM;

        // 3. Counting good subarrays ending at j

        // Convert M to an array of [V, R] pairs and sort by R ascending
        let sortedEntries = Array.from(M.entries()).map(([V, R]) => ({ V, R }));
        sortedEntries.sort((a, b) => a.R - b.R);

        let currentCountJ = 0;
        let R_prev = j + 1; // R_prev holds the starting index of the next segment (to the right)

        // Iterate backwards through the sorted list to determine segment lengths easily
        // Since we sorted by R ascending, we iterate from the end (largest R) down to the start (smallest R).
        for (let k = sortedEntries.length - 1; k >= 0; k--) {
            const { V, R } = sortedEntries[k];

            // R is the start index of this OR value V. 
            // The segment ends just before the next larger R value (which is R_prev).
            let R_start = R;
            let R_end = R_prev - 1;

            // Safety check: R_end must be <= j
            if (R_end > j) {
                 R_end = j;
            }

            if (R_start > R_end) {
                // This should ideally not happen if M was correctly constructed and R_prev is handled.
                R_prev = R;
                continue;
            }

            // Length of the segment [R_start, R_end] where OR is V
            const segmentLength = R_end - R_start + 1;

            // Check condition: Is V present in nums[R_start ... j]?
            // Since V = OR(nums[R_start...j]), if V is present, it must be present in the range [R_start, j].

            if (valueToIndices.has(V)) {
                const indices = valueToIndices.get(V);

                // Binary search for the smallest index l >= R_start
                let low = 0;
                let high = indices.length - 1;
                let found = -1;

                while (low <= high) {
                    let mid = Math.floor((low + high) / 2);
                    if (indices[mid] >= R_start) {
                        found = indices[mid];
                        high = mid - 1; // Try to find an even smaller index
                    } else {
                        low = mid + 1;
                    }
                }

                // If found and the occurrence is within the current subarray end j
                if (found !== -1 && found <= j) {
                    // All subarrays in this segment are good because V is present in nums[R_start...j]
                    currentCountJ += segmentLength;
                }
            }

            // Update R_prev for the next (smaller R) segment
            R_prev = R;
        }

        totalCount += currentCountJ;
    }

    return totalCount;
}

